    public Dictionary<string, string> ParseConfigurationWithXmlReader(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD,
            XmlResolver = new XmlUrlResolver(),
            IgnoreWhitespace = true,
            IgnoreComments = true
        };

        using (var reader = XmlReader.Create(xmlFilePath, readerSettings))
        {
            string currentPath = "";
            string currentElement = "";

            while (reader.Read())
            {
                switch (reader.NodeType)
                {
                    case XmlNodeType.Element:
                        currentElement = reader.Name;
                        currentPath = string.IsNullOrEmpty(currentPath) ? currentElement : currentPath + "." + currentElement;

                        if (reader.HasAttributes)
                        {
                            while (reader.MoveToNextAttribute())
                            {
                                string key = currentPath + "[@" + reader.Name + "]";
                                settings[key] = reader.Value;
                            }
                            reader.MoveToElement();
                        }

                        if (reader.IsEmptyElement)
                        {
                            currentPath = GetParentPath(currentPath);
                        }
                        break;

                    case XmlNodeType.Text:
                        settings[currentPath] = reader.Value;
                        break;

                    case XmlNodeType.EndElement:
                        currentPath = GetParentPath(currentPath);
                        break;
                }
            }
        }

        return settings;
    }

    public Dictionary<string, string> ParseConfigurationFromString(string xmlContent)
    {
        var settings = new Dictionary<string, string>();
        
        var xmlDoc = new XmlDocument();
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD,
            XmlResolver = new XmlUrlResolver()
        };

        using (var stringReader = new StringReader(xmlContent))
        using (var reader = XmlReader.Create(stringReader, readerSettings))
        {
            xmlDoc.Load(reader);
        }

        ExtractSettings(xmlDoc.DocumentElement, settings, "");

        return settings;
    }

    private void ExtractSettings(XmlNode node, Dictionary<string, string> settings, string path)
    {
        if (node == null) return;

        string currentPath = string.IsNullOrEmpty(path) ? node.Name : path + "." + node.Name;

        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string key = currentPath + "[@" + attr.Name + "]";
                settings[key] = attr.Value;
            }
        }

        if (node.HasChildNodes)
        {
            bool hasElementChildren = false;
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    hasElementChildren = true;
                    ExtractSettings(child, settings, currentPath);
                }
            }

            if (!hasElementChildren && node.NodeType == XmlNodeType.Element)
            {
                settings[currentPath] = node.InnerText.Trim();
            }
        }
        else if (node.NodeType == XmlNodeType.Element)
        {
            settings[currentPath] = node.InnerText.Trim();
        }
    }

    private string GetParentPath(string path)
    {
        if (string.IsNullOrEmpty(path)) return "";
        
        int lastDotIndex = path.LastIndexOf('.');
        return lastDotIndex > 0 ? path.Substring(0, lastDotIndex) : "";
    }

